
"use client"

import { useState, useMemo, useEffect, use } from "react";
import Link from "next/link";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Badge } from "@/components/ui/badge";
import { Card } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Trophy, Medal, MapPin, Zap, Crown, Loader2, Star, Target, ChevronRight } from "lucide-react";
import { cn } from "@/lib/utils";
import { useUser, useFirestore, useCollection, useMemoFirebase } from "@/firebase";
import { collection, query, orderBy, limit } from "firebase/firestore";
import { RenderCarIcon } from "@/components/icons/car-icons";

const KOSOVO_CITIES = [
  "Mbarë Kosova", "Prishtinë", "Prizren", "Pejë", "Gjakovë", "Mitrovicë", "Gjilan", "Ferizaj", 
  "Vushtrri", "Podujevë", "Rahovec", "Fushë Kosovë", "Suharekë", "Kaçanik", 
  "Skënderaj", "Lipjan", "Malishevë", "Drenas", "Deçan", "Klinë", "Kamenicë", 
  "Dragash", "Istog", "Viti", "Obiliq", "Leposaviq", "Graçanicë", "Hani i Elezit", 
  "Zveçan", "Shtime", "Novobërdë", "Zubin Potok", "Junik", "Mamushë", 
  "Ranillug", "Partesh", "Kllokot"
];

export default function LeaderboardPage({ searchParams }: { searchParams: Promise<any> }) {
  // Next.js 15 unwrapping
  use(searchParams);
  
  const { user, isUserLoading } = useUser();
  const [activeTab, setActiveTab] = useState("top-speed");
  const [cityFilter, setCityFilter] = useState("Mbarë Kosova");
  const db = useFirestore();
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  const publicRunsQuery = useMemoFirebase(() => {
    if (!db || isUserLoading || !user?.uid) return null;
    return query(
      collection(db, "public_runs"),
      orderBy("createdAt", "desc"),
      limit(1000)
    );
  }, [db, isUserLoading, user?.uid]);

  const { data: allRuns, isLoading } = useCollection(publicRunsQuery);

  const filteredRuns = useMemo(() => {
    if (!allRuns) return [];
    if (cityFilter === "Mbarë Kosova") return allRuns;
    return allRuns.filter(run => run.city === cityFilter);
  }, [allRuns, cityFilter]);

  const topSpeedRankings = useMemo(() => {
    const uniqueUsers: Record<string, any> = {};
    filteredRuns.forEach(run => {
      if (!uniqueUsers[run.userId] || (run.peakSpeedKmH || 0) > (uniqueUsers[run.userId].peakSpeedKmH || 0)) {
        uniqueUsers[run.userId] = run;
      }
    });
    return Object.values(uniqueUsers).sort((a: any, b: any) => (b.peakSpeedKmH || 0) - (a.peakSpeedKmH || 0));
  }, [filteredRuns]);

  const dragRankings = (type: string) => {
    const uniqueUsers: Record<string, any> = {};
    filteredRuns.filter(r => r.runType === type && r.dragTime).forEach(run => {
      if (!uniqueUsers[run.userId] || run.dragTime < uniqueUsers[run.userId].dragTime) {
        uniqueUsers[run.userId] = run;
      }
    });
    return Object.values(uniqueUsers).sort((a: any, b: any) => (a.dragTime || 999) - (b.dragTime || 999));
  };

  const zeroTo60Rankings = useMemo(() => dragRankings('0-60'), [filteredRuns]);
  const zeroTo100Rankings = useMemo(() => dragRankings('0-100'), [filteredRuns]);
  const hundredTo200Rankings = useMemo(() => dragRankings('100-200'), [filteredRuns]);
  const quarterMileRankings = useMemo(() => dragRankings('1/4 Mile'), [filteredRuns]);

  const globalBestInKosovo = useMemo(() => {
    if (!allRuns) return {};
    const bests: Record<string, number> = {};
    bests['top-speed'] = Math.max(...allRuns.map(r => r.peakSpeedKmH || 0), 0);
    ['0-60', '0-100', '100-200', '1/4 Mile'].forEach(type => {
      const typeRuns = allRuns.filter(r => r.runType === type && r.dragTime);
      if (typeRuns.length > 0) {
        bests[type] = Math.min(...typeRuns.map(r => r.dragTime));
      }
    });
    return bests;
  }, [allRuns]);

  if (!mounted || isUserLoading) return <div className="min-h-screen bg-background flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-accent" /></div>;

  return (
    <div className="flex flex-col min-h-screen bg-background text-foreground pb-24 safe-top relative no-scrollbar">
      <div className="absolute top-0 left-0 right-0 h-56 bg-gradient-to-b from-red-600/10 via-transparent to-transparent pointer-events-none" />
      
      <div className="p-8 pb-4 relative z-10 space-y-6">
        <div className="flex items-center gap-4 apple-slide-up">
          <div className="w-12 h-12 bg-red-600/15 rounded-2xl flex items-center justify-center border border-red-500/20 shadow-xl">
            <Trophy className="w-7 h-7 text-red-500" />
          </div>
          <div>
            <h1 className="text-2xl font-black tracking-tighter uppercase leading-none">RANKINGU</h1>
            <p className="text-[10px] text-muted-foreground uppercase font-black tracking-[0.4em] mt-1.5">LIVE NË KOSOVË</p>
          </div>
        </div>

        <div className="space-y-2 apple-slide-up stagger-1">
          <Label className="text-[10px] font-black uppercase text-muted-foreground px-1 tracking-widest">📍 FILTRO SIPAS QYTETIT</Label>
          <Select value={cityFilter} onValueChange={setCityFilter}>
            <SelectTrigger className="w-full h-14 glass border-white/10 rounded-2xl font-black uppercase text-[11px] bg-white/5 transition-all duration-300 hover:border-accent/40">
              <SelectValue placeholder="Zgjidh Qytetin" />
            </SelectTrigger>
            <SelectContent className="glass border-white/10 max-h-[300px]">
              {KOSOVO_CITIES.map(c => (
                <SelectItem key={c} value={c} className="font-black text-[11px] uppercase py-3">📍 {c}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </div>

      <Tabs defaultValue="top-speed" onValueChange={setActiveTab} className="w-full px-5 mt-4 relative z-10 apple-slide-up stagger-2">
        <TabsList className="flex gap-2 overflow-x-auto no-scrollbar glass border-white/5 h-14 rounded-[1.5rem] p-1.5 shrink-0 mb-8 bg-white/5">
          <TabsTrigger value="top-speed" className="rounded-xl flex-1 data-[state=active]:bg-red-600 data-[state=active]:text-white font-black text-[9px] uppercase px-4 transition-all duration-300">TOP SPEED</TabsTrigger>
          <TabsTrigger value="0-60" className="rounded-xl flex-1 data-[state=active]:bg-accent data-[state=active]:text-background font-black text-[9px] uppercase px-4 transition-all duration-300">0-60</TabsTrigger>
          <TabsTrigger value="0-100" className="rounded-xl flex-1 data-[state=active]:bg-accent data-[state=active]:text-background font-black text-[9px] uppercase px-4 transition-all duration-300">0-100</TabsTrigger>
          <TabsTrigger value="100-200" className="rounded-xl flex-1 data-[state=active]:bg-accent data-[state=active]:text-background font-black text-[9px] uppercase px-4 transition-all duration-300">100-200</TabsTrigger>
          <TabsTrigger value="1/4mile" className="rounded-xl flex-1 data-[state=active]:bg-accent data-[state=active]:text-background font-black text-[9px] uppercase px-4 transition-all duration-300">1/4 MILE</TabsTrigger>
        </TabsList>

        <div className="space-y-3">
          <TabsContent value="top-speed" className="m-0 space-y-3 focus-visible:outline-none">
            {topSpeedRankings.map((run: any, index: number) => (
              <LeaderboardCard 
                key={run.id} 
                driver={run} 
                index={index} 
                metric={`${run.peakSpeedKmH} km/h`} 
                isGlobalTop={run.peakSpeedKmH >= (globalBestInKosovo['top-speed'] || 0)}
                currentCity={cityFilter}
              />
            ))}
          </TabsContent>

          <TabsContent value="0-60" className="m-0 space-y-3 focus-visible:outline-none">
            {zeroTo60Rankings.map((run: any, index: number) => (
              <LeaderboardCard 
                key={run.id} 
                driver={run} 
                index={index} 
                metric={`${run.dragTime?.toFixed(2)}s`} 
                isGlobalTop={run.dragTime <= (globalBestInKosovo['0-60'] || 999)}
                currentCity={cityFilter}
              />
            ))}
          </TabsContent>

          <TabsContent value="0-100" className="m-0 space-y-3 focus-visible:outline-none">
            {zeroTo100Rankings.map((run: any, index: number) => (
              <LeaderboardCard 
                key={run.id} 
                driver={run} 
                index={index} 
                metric={`${run.dragTime?.toFixed(2)}s`} 
                isGlobalTop={run.dragTime <= (globalBestInKosovo['0-100'] || 999)}
                currentCity={cityFilter}
              />
            ))}
          </TabsContent>

          <TabsContent value="100-200" className="m-0 space-y-3 focus-visible:outline-none">
            {hundredTo200Rankings.map((run: any, index: number) => (
              <LeaderboardCard 
                key={run.id} 
                driver={run} 
                index={index} 
                metric={`${run.dragTime?.toFixed(2)}s`} 
                isGlobalTop={run.dragTime <= (globalBestInKosovo['100-200'] || 999)}
                currentCity={cityFilter}
              />
            ))}
          </TabsContent>

          <TabsContent value="1/4mile" className="m-0 space-y-3 focus-visible:outline-none">
            {quarterMileRankings.map((run: any, index: number) => (
              <LeaderboardCard 
                key={run.id} 
                driver={run} 
                index={index} 
                metric={`${run.dragTime?.toFixed(2)}s`} 
                isGlobalTop={run.dragTime <= (globalBestInKosovo['1/4 Mile'] || 999)}
                currentCity={cityFilter}
              />
            ))}
          </TabsContent>
          
          {!isLoading && filteredRuns.length === 0 && (
            <div className="py-24 text-center opacity-40">
              <p className="text-[11px] font-black uppercase tracking-widest">Nuk ka rekorde për këtë qytet.</p>
            </div>
          )}
        </div>
      </Tabs>
      <BottomNav />
    </div>
  );
}

function LeaderboardCard({ 
  driver, 
  index, 
  metric, 
  isGlobalTop,
  currentCity 
}: { 
  driver: any, 
  index: number, 
  metric: string, 
  isGlobalTop?: boolean,
  currentCity?: string
}) {
  const isFirst = index === 0;
  
  // Limiting stagger for cards to keep it smooth
  const staggerClass = index < 10 ? `stagger-${Math.min(index + 1, 5)}` : '';

  return (
    <Card className={cn(
      "glass-card p-4 px-6 relative overflow-hidden group transition-all duration-300 rounded-[1.8rem] border-white/5 apple-slide-up",
      staggerClass,
      isFirst && "border-accent/30 bg-gradient-to-br from-accent/10 to-transparent shadow-xl"
    )}>
      {isFirst && (
        <div className="absolute top-0 right-0 px-4 py-1.5 bg-accent text-background rounded-bl-[1.2rem] flex items-center gap-2 shadow-lg z-20 apple-scale-in stagger-3">
          <Crown className="w-3.5 h-3.5 fill-current" />
          <span className="text-[9px] font-black uppercase tracking-tight">
            {isGlobalTop || currentCity === 'Mbarë Kosova' ? 'NR. 1 NË KOSOVË' : `NR. 1 NË ${currentCity.toUpperCase()}`}
          </span>
        </div>
      )}

      <div className="flex items-center gap-5 relative z-10 h-12">
        <div className="flex flex-col items-center justify-center min-w-[32px]">
          {index === 0 ? <Trophy className="w-6 h-6 text-accent" /> : 
           index === 1 ? <Medal className="w-6 h-6 text-zinc-400" /> :
           index === 2 ? <Medal className="w-6 h-6 text-orange-600" /> :
           <span className="text-[12px] font-black text-muted-foreground/30 italic">#{index + 1}</span>}
        </div>
        
        <Link href={`/profile/${driver.userId}`} className="w-11 h-11 rounded-2xl bg-zinc-950 border border-white/5 flex items-center justify-center shadow-lg shrink-0 overflow-hidden transition-transform active:scale-90">
           <RenderCarIcon type={driver.profileIcon} className="w-6 h-6 text-accent" />
        </Link>

        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <h3 className="font-black text-sm truncate uppercase text-white">{driver.username}</h3>
            {isFirst && <Star className="w-3 h-3 text-accent fill-accent animate-pulse" />}
          </div>
          <div className="flex items-center gap-2 leading-none mt-1">
            <MapPin className="w-3 h-3 text-accent" />
            <span className="text-[8px] font-black text-muted-foreground uppercase tracking-widest">{driver.city}</span>
            <span className="text-[8px] font-medium text-muted-foreground/50 truncate uppercase ml-1">{driver.carBrand} {driver.carModel}</span>
          </div>
        </div>

        <div className="text-right flex flex-col items-end">
          <div className={cn(
            "text-xl font-black leading-none",
            isFirst ? "text-accent" : "text-white"
          )}>
            {metric.split(' ')[0]}
          </div>
          <div className="text-[9px] font-black text-muted-foreground uppercase tracking-widest leading-none mt-1.5">{metric.split(' ')[1]}</div>
        </div>
      </div>
    </Card>
  );
}
